use poseidon::poseidon2::Poseidon2;

// Universal ICAO date predicate: date_field >= threshold
// Works with any DD/MM/YYYY date field in DG13 (DOB, issueDate, expiryDate).
// tag_id is a public input - verifier specifies which field to prove.
// leaf_index is derived from tag_id (leaf_index = tag_id - 1).

fn main(
    siblings: [Field; 5],
    length: Field,
    data: [Field; 4],
    packed_hash: Field,
    date_bytes: [u8; 10],
    commitment: pub Field,
    salt: pub Field,
    tag_id: pub Field,
    threshold: pub u32,
) {
    assert(length == 10, "length must be 10 (DD/MM/YYYY)");

    let leaf = Poseidon2::hash([tag_id, length, data[0], data[1], data[2], data[3], salt, packed_hash], 8);

    let leaf_index: u32 = tag_id as u32 - 1;

    let mut current = leaf;

    for level in 0..5 {
        let bit = (leaf_index >> level) & 1;

        let pair = if bit == 0 {
            [current, siblings[level]]
        } else {
            [siblings[level], current]
        };

        current = Poseidon2::hash(pair, 2);
    }

    assert(Poseidon2::hash([current, salt], 2) == commitment, "commitment mismatch");

    let mut packed_check: Field = 0;

    for b in 0..10 {
        packed_check = packed_check * 256 + date_bytes[b] as Field;
    }

    assert(packed_check == data[0], "date_bytes != data[0]");

    assert(data[1] == 0, "data[1] must be 0");

    assert(data[2] == 0, "data[2] must be 0");

    assert(data[3] == 0, "data[3] must be 0");

    assert(date_bytes[2] == 0x2F, "missing / separator");

    assert(date_bytes[5] == 0x2F, "missing / separator");

    for i in 0..10 {
        if (i != 2) & (i != 5) {
            assert(date_bytes[i] >= 0x30, "invalid digit");

            assert(date_bytes[i] <= 0x39, "invalid digit");
        }
    }

    let day: u32 = ((date_bytes[0] - 0x30) as u32) * 10 + (date_bytes[1] - 0x30) as u32;

    let month: u32 = ((date_bytes[3] - 0x30) as u32) * 10 + (date_bytes[4] - 0x30) as u32;

    let year: u32 = ((date_bytes[6] - 0x30) as u32) * 1000
        + ((date_bytes[7] - 0x30) as u32) * 100
        + ((date_bytes[8] - 0x30) as u32) * 10
        + (date_bytes[9] - 0x30) as u32;

    let date_int: u32 = year * 10000 + month * 100 + day;

    assert(date_int >= threshold, "date field not greater than or equal to threshold");
}

